 31→var connectCmd = &cobra.Command{
 32→	Use:     "connect [name] [-- ssh-options...]",
 33→	Aliases: []string{"c"},
 34→	Short:   "Connect to sandbox and attach tmux (auto-starts if stopped)",
 35→	Args:  cobra.ArbitraryArgs,
 36→	RunE: func(cmd *cobra.Command, args []string) error {
 37→		name, passthrough := splitArgs(args)
 38→		if name == "" {
 39→			return fmt.Errorf("specify a sandbox name or set one with: sandcastle use <name>")
 40→		}
 41→
 42→		client, err := api.NewClient()
 43→		if err != nil {
 44→			return err
 45→		}
 46→		printServer(client)
 47→
 48→		sandbox, err := findSandboxByName(client, name)
 49→		if err != nil {
 50→			return err
 51→		}
 52→
 53→		// Auto-start if stopped
 54→		if sandbox.Status == "stopped" {
 55→			fmt.Printf("Starting sandbox %q...\n", name)
 56→			sandbox, err = client.StartSandbox(sandbox.ID)
 57→			if err != nil {
 58→				return fmt.Errorf("failed to start sandbox: %w", err)
 59→			}
 60→		}
 61→
 62→		info, err := client.ConnectInfo(sandbox.ID)
 63→		if err != nil {
 64→			return err
 65→		}
 66→
 67→		if err := waitForSSH(info.Host, info.Port); err != nil {
 68→			return err
 69→		}
 70→
 71→		cfg, err := config.Load()
 72→		if err != nil {
 73→			return err
 74→		}
 75→		prefs := cfg.LoadPreferences()
 76→
 77→		var remoteCmd string
 78→		if *prefs.UseTmux {
 79→			remoteCmd = tmuxCmd
 80→		}
 81→
 82→		protocol := resolveProtocol(cmd, cfg, info.Host, info.Port, info.User, prefs.SSHExtraArgs)
 83→
 84→		if protocol == "mosh" {
 85→			fmt.Fprintf(os.Stderr, "\033[33mWarning:\033[0m mosh does not support SSH agent forwarding. Use --mosh=no if you need ssh-add keys inside the sandbox.\n")
 86→			return moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs, passthrough)
 87→		}
 88→		return sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs, passthrough)
 89→	},
 90→}
