152→func resolveProtocol(cmd *cobra.Command, cfg *config.Config, host string, port int, user, extraArgs string) string {
153→	if cmd.Flags().Changed("mosh") {
154→		switch strings.ToLower(connectMoshFlag) {
155→		case "yes", "true", "1":
156→			return "mosh"
157→		case "no", "false", "0":
158→			return "ssh"
159→		default:
160→			return "ssh"
161→		}
162→	}
163→	return pickProtocol(cfg, host, port, user, extraArgs)
164→}
