199→func sshExec(host string, port int, user string, remoteCmd string, extraArgs string, passthrough []string) error {
200→	sshArgs := []string{
201→		"-A",
202→		"-p", strconv.Itoa(port),
203→		"-o", "StrictHostKeyChecking=no",
204→		"-o", "UserKnownHostsFile=/dev/null",
205→		"-o", "LogLevel=ERROR",
206→	}
207→	if extraArgs != "" {
208→		sshArgs = append(sshArgs, strings.Fields(extraArgs)...)
209→	}
210→	sshArgs = append(sshArgs, passthrough...)
211→	sshArgs = append(sshArgs, fmt.Sprintf("%s@%s", user, host))
212→	if remoteCmd != "" {
213→		sshArgs = append(sshArgs, "-t", remoteCmd)
214→	}
215→
216→	sshPath, err := exec.LookPath("ssh")
217→	if err != nil {
218→		return fmt.Errorf("ssh not found: %w", err)
219→	}
220→
221→	if os.Getenv("VERBOSE") == "1" {
222→		fmt.Fprintf(os.Stderr, "→ ssh %s\n", shellJoin(sshArgs))
223→	}
224→
225→	proc := &os.ProcAttr{
226→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
227→	}
228→	process, err := os.StartProcess(sshPath, append([]string{"ssh"}, sshArgs...), proc)
229→	if err != nil {
230→		return fmt.Errorf("starting ssh: %w", err)
231→	}
232→
233→	state, err := process.Wait()
234→	if err != nil {
235→		return err
236→	}
237→	if !state.Success() {
238→		os.Exit(state.ExitCode())
239→	}
240→	return nil
241→}
