243→func moshExec(host string, port int, user string, remoteCmd string, extraArgs string, passthrough []string) error {
244→	sshOpts := fmt.Sprintf("ssh -A -p %d -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR", port)
245→	if extraArgs != "" {
246→		sshOpts += " " + extraArgs
247→	}
248→	if len(passthrough) > 0 {
249→		sshOpts += " " + strings.Join(passthrough, " ")
250→	}
251→
252→	moshArgs := []string{
253→		"--ssh=" + sshOpts,
254→		fmt.Sprintf("%s@%s", user, host),
255→	}
256→	if remoteCmd != "" {
257→		moshArgs = append(moshArgs, "--", remoteCmd)
258→	}
259→
260→	moshPath, err := exec.LookPath("mosh")
261→	if err != nil {
262→		return fmt.Errorf("mosh not found in PATH — install mosh on your local machine first (https://mosh.org): %w", err)
263→	}
264→
265→	if os.Getenv("VERBOSE") == "1" {
266→		fmt.Fprintf(os.Stderr, "→ mosh %s\n", shellJoin(moshArgs))
267→	}
268→
269→	proc := &os.ProcAttr{
270→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
271→	}
272→	process, err := os.StartProcess(moshPath, append([]string{"mosh"}, moshArgs...), proc)
273→	if err != nil {
274→		return fmt.Errorf("starting mosh: %w", err)
275→	}
276→
277→	state, err := process.Wait()
278→	if err != nil {
279→		return err
280→	}
281→	if !state.Success() {
282→		os.Exit(state.ExitCode())
283→	}
284→	return nil
285→}
