287→// moshAvailableLocally reports whether mosh is installed on this machine.
288→func moshAvailableLocally() bool {
289→	_, err := exec.LookPath("mosh")
290→	return err == nil
291→}
292→
293→// moshAvailableRemotely probes the remote host by running `which mosh` over SSH.
294→func moshAvailableRemotely(host string, port int, user, extraArgs string) bool {
295→	sshArgs := []string{
296→		"-p", strconv.Itoa(port),
297→		"-o", "StrictHostKeyChecking=no",
298→		"-o", "UserKnownHostsFile=/dev/null",
299→		"-o", "LogLevel=ERROR",
300→		"-o", "ConnectTimeout=5",
301→	}
302→	if extraArgs != "" {
303→		sshArgs = append(sshArgs, strings.Fields(extraArgs)...)
304→	}
305→	sshArgs = append(sshArgs, fmt.Sprintf("%s@%s", user, host), "which mosh")
306→
307→	ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
308→	defer cancel()
309→	return exec.CommandContext(ctx, "ssh", sshArgs...).Run() == nil
310→}
311→
312→// pickProtocol returns "mosh" or "ssh". Defaults to SSH (which supports
313→// agent forwarding). Mosh can be selected with --mosh flag,
314→// SANDCASTLE_CONNECT_PROTOCOL env var, or `sc config set connect-protocol mosh`.
315→func pickProtocol(cfg *config.Config, host string, port int, user, extraArgs string) string {
316→	if os.Getenv("SANDCASTLE_CONNECT_PROTOCOL") != "" || cfg.Preferences.ConnectProtocol != "" {
317→		return cfg.LoadPreferences().ConnectProtocol
318→	}
319→	return "ssh"
320→}
321→
322→func shellJoin(args []string) string {
323→	quoted := make([]string, len(args))
324→	for i, a := range args {
325→		if strings.ContainsAny(a, " \t\n\"'\\") {
326→			quoted[i] = fmt.Sprintf("%q", a)
327→		} else {
328→			quoted[i] = a
329→		}
330→	}
331→	return strings.Join(quoted, " ")
332→}
