  1→package config
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"strings"
  8→
  9→	"gopkg.in/yaml.v3"
 10→)
 11→
 12→type ServerConfig struct {
 13→	URL      string `yaml:"url"`
 14→	Token    string `yaml:"token"`
 15→	Insecure bool   `yaml:"insecure,omitempty"`
 16→}
 17→
 18→// Preferences holds user-configurable CLI behaviour. Each field can be
 19→// overridden by a SANDCASTLE_<KEY> environment variable at runtime.
 20→type Preferences struct {
 21→	ConnectProtocol string `yaml:"connect_protocol,omitempty"` // "ssh" (default) | "mosh"
 22→	UseTmux         *bool  `yaml:"use_tmux,omitempty"`         // default true
 23→	SSHExtraArgs    string `yaml:"ssh_extra_args,omitempty"`   // extra flags for ssh/mosh
 24→	MountHome       *bool  `yaml:"mount_home,omitempty"`       // default false; --home on create
 25→	DataPath        string `yaml:"data_path,omitempty"`        // default ""; --data on create
 26→	VNC             *bool  `yaml:"vnc,omitempty"`              // default true; false → --no-vnc on create
 27→	Docker          *bool  `yaml:"docker,omitempty"`           // default true; false → --no-docker on create
 28→}
 29→
 30→type Config struct {
 31→	CurrentServer string                  `yaml:"current_server"`
 32→	Servers       map[string]ServerConfig `yaml:"servers"`
 33→	Preferences   Preferences             `yaml:"preferences,omitempty"`
 34→}
 35→
 36→// legacyConfig is the old flat format for migration.
 37→type legacyConfig struct {
 38→	Server string `yaml:"server"`
 39→	Token  string `yaml:"token"`
 40→}
 41→
 42→func Dir() string {
 43→	home, _ := os.UserHomeDir()
 44→	return filepath.Join(home, ".sandcastle")
 45→}
 46→
 47→func Path() string {
 48→	return filepath.Join(Dir(), "config.yaml")
 49→}
 50→
 51→func Load() (*Config, error) {
 52→	cfg := &Config{Servers: make(map[string]ServerConfig)}
 53→	data, err := os.ReadFile(Path())
 54→	if err != nil {
 55→		if os.IsNotExist(err) {
 56→			return cfg, nil
 57→		}
 58→		return nil, fmt.Errorf("reading config: %w", err)
 59→	}
 60→
 61→	// Try new format first
 62→	if err := yaml.Unmarshal(data, cfg); err != nil {
 63→		return nil, fmt.Errorf("parsing config: %w", err)
 64→	}
 65→
 66→	// Migrate legacy flat format
 67→	if cfg.Servers == nil || len(cfg.Servers) == 0 {
 68→		var legacy legacyConfig
 69→		if err := yaml.Unmarshal(data, &legacy); err == nil && legacy.Server != "" {
 70→			cfg.Servers = map[string]ServerConfig{
 71→				"default": {URL: legacy.Server, Token: legacy.Token},
 72→			}
 73→			cfg.CurrentServer = "default"
 74→			// Save migrated config
 75→			_ = Save(cfg)
 76→		}
 77→	}
 78→
 79→	if cfg.Servers == nil {
 80→		cfg.Servers = make(map[string]ServerConfig)
 81→	}
 82→
 83→	return cfg, nil
 84→}
 85→
 86→func Save(cfg *Config) error {
 87→	if err := os.MkdirAll(Dir(), 0o700); err != nil {
 88→		return fmt.Errorf("creating config dir: %w", err)
 89→	}
 90→	data, err := yaml.Marshal(cfg)
 91→	if err != nil {
 92→		return fmt.Errorf("marshaling config: %w", err)
 93→	}
 94→	if err := os.WriteFile(Path(), data, 0o600); err != nil {
 95→		return fmt.Errorf("writing config: %w", err)
 96→	}
 97→	return nil
 98→}
 99→
100→// CurrentServerConfig returns the active server's URL and token.
101→func (c *Config) CurrentServerConfig() (ServerConfig, error) {
102→	if c.CurrentServer == "" {
103→		return ServerConfig{}, fmt.Errorf("no server configured — run: sandcastle login <url>")
104→	}
105→	srv, ok := c.Servers[c.CurrentServer]
106→	if !ok {
107→		return ServerConfig{}, fmt.Errorf("server %q not found in config — run: sandcastle login <url>", c.CurrentServer)
108→	}
109→	return srv, nil
110→}
111→
112→// SetServer adds or updates a server and sets it as current.
113→func (c *Config) SetServer(alias, url, token string, insecure bool) {
114→	if c.Servers == nil {
115→		c.Servers = make(map[string]ServerConfig)
116→	}
117→	c.Servers[alias] = ServerConfig{URL: url, Token: token, Insecure: insecure}
118→	c.CurrentServer = alias
119→}
120→
121→// LoadPreferences returns effective preferences with env vars overlaid.
122→// Priority: ENV var > config file preference > built-in default.
123→func (c *Config) LoadPreferences() Preferences {
124→	p := c.Preferences
125→
126→	if v := os.Getenv("SANDCASTLE_CONNECT_PROTOCOL"); v != "" {
127→		p.ConnectProtocol = v
128→	}
129→	if v := os.Getenv("SANDCASTLE_USE_TMUX"); v != "" {
130→		b := strings.ToLower(v) == "true" || v == "1"
131→		p.UseTmux = &b
132→	}
133→	if v := os.Getenv("SANDCASTLE_SSH_EXTRA_ARGS"); v != "" {
134→		p.SSHExtraArgs = v
135→	}
136→	if v := os.Getenv("SANDCASTLE_HOME"); v != "" {
137→		b := strings.ToLower(v) == "true" || v == "1"
138→		p.MountHome = &b
139→	}
140→	if v := os.Getenv("SANDCASTLE_DATA"); v != "" {
141→		if v == "1" || v == "true" {
142→			v = "."
143→		}
144→		p.DataPath = v
145→	}
146→	if v := os.Getenv("SANDCASTLE_VNC"); v != "" {
147→		b := strings.ToLower(v) == "true" || v == "1"
148→		p.VNC = &b
149→	}
150→	if v := os.Getenv("SANDCASTLE_DOCKER"); v != "" {
151→		b := strings.ToLower(v) == "true" || v == "1"
152→		p.Docker = &b
153→	}
154→
155→	// Apply built-in defaults
156→	if p.ConnectProtocol == "" {
157→		p.ConnectProtocol = "ssh"
158→	}
159→	if p.UseTmux == nil {
160→		t := true
161→		p.UseTmux = &t
162→	}
163→
164→	return p
165→}
166→
167→// SetPreference sets a named preference by string value and validates it.
168→func (c *Config) SetPreference(key, value string) error {
169→	switch key {
170→	case "connect_protocol":
171→		if value != "ssh" && value != "mosh" && value != "auto" {
172→			return fmt.Errorf("connect_protocol must be 'ssh', 'mosh', or 'auto', got %q", value)
173→		}
174→		if value == "auto" {
175→			c.Preferences.ConnectProtocol = ""
176→		} else {
177→			c.Preferences.ConnectProtocol = value
178→		}
179→	case "use_tmux":
180→		switch strings.ToLower(value) {
181→		case "true", "1", "yes":
182→			t := true
183→			c.Preferences.UseTmux = &t
184→		case "false", "0", "no":
185→			f := false
186→			c.Preferences.UseTmux = &f
187→		default:
188→			return fmt.Errorf("use_tmux must be 'true' or 'false', got %q", value)
189→		}
190→	case "ssh_extra_args":
191→		c.Preferences.SSHExtraArgs = value
192→	case "mount_home":
193→		switch strings.ToLower(value) {
194→		case "true", "1", "yes":
195→			t := true
196→			c.Preferences.MountHome = &t
197→		case "false", "0", "no":
198→			f := false
199→			c.Preferences.MountHome = &f
200→		default:
201→			return fmt.Errorf("mount_home must be 'true' or 'false', got %q", value)
202→		}
203→	case "data_path":
204→		if value == "false" || value == "0" || value == "no" || value == "off" {
205→			c.Preferences.DataPath = ""
206→		} else {
207→			if value == "true" || value == "1" {
208→				value = "."
209→			}
210→			c.Preferences.DataPath = value
211→		}
212→	case "vnc":
213→		switch strings.ToLower(value) {
214→		case "true", "1", "yes":
215→			t := true
216→			c.Preferences.VNC = &t
217→		case "false", "0", "no":
218→			f := false
219→			c.Preferences.VNC = &f
220→		default:
221→			return fmt.Errorf("vnc must be 'true' or 'false', got %q", value)
222→		}
223→	case "docker":
224→		switch strings.ToLower(value) {
225→		case "true", "1", "yes":
226→			t := true
227→			c.Preferences.Docker = &t
228→		case "false", "0", "no":
229→			f := false
230→			c.Preferences.Docker = &f
231→		default:
232→			return fmt.Errorf("docker must be 'true' or 'false', got %q", value)
233→		}
234→	default:
