166→func waitForSSH(host string, port int) error {
167→	addr := net.JoinHostPort(host, strconv.Itoa(port))
168→	deadline := time.Now().Add(30 * time.Second)
169→	printed := false
170→
171→	if os.Getenv("VERBOSE") == "1" {
172→		fmt.Fprintf(os.Stderr, "\033[2m[verbose] Waiting for SSH at %s (timeout: 30s)\033[0m\n", addr)
173→	}
174→
175→	for time.Now().Before(deadline) {
176→		conn, err := net.DialTimeout("tcp", addr, time.Second)
177→		if err == nil {
178→			conn.Close()
179→			if printed {
180→				fmt.Println()
181→			}
182→			if os.Getenv("VERBOSE") == "1" {
183→				fmt.Fprintf(os.Stderr, "\033[2m[verbose] SSH connection successful!\033[0m\n")
184→			}
185→			return nil
186→		}
187→		if !printed {
188→			fmt.Printf("Waiting for SSH to be ready...")
189→			printed = true
190→		}
191→		fmt.Print(".")
192→		time.Sleep(500 * time.Millisecond)
193→	}
194→
195→	fmt.Println()
196→	return fmt.Errorf("timeout waiting for SSH at %s", addr)
197→}
